#!/bin/bash`n# в•”в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•—`n# в•‘          CubiVeil вЂ” Test Suite                            в•‘`n# в•‘          github.com/cubiculus/cubiveil                    в•‘`n# в•‘                                                           в•‘`n# в•‘  РљРѕРјРїР»РµРєСЃРЅРѕРµ С‚РµСЃС‚РёСЂРѕРІР°РЅРёРµ РІСЃРµС… РјРѕРґСѓР»РµР№                    в•‘`n# в•љв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ќ`n`n# в”Ђв”Ђ РџРѕРґРєР»СЋС‡РµРЅРёРµ Р·Р°РІРёСЃРёРјРѕСЃС‚РµР№ / Dependencies в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`nSCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"`n`n# РџРѕРґРєР»СЋС‡Р°РµРј core РјРѕРґСѓР»Рё`nif [[ -f "${SCRIPT_DIR}/lib/core/system.sh" ]]; then`n  source "${SCRIPT_DIR}/lib/core/system.sh"`nfi`n`nif [[ -f "${SCRIPT_DIR}/lib/core/log.sh" ]]; then`n  source "${SCRIPT_DIR}/lib/core/log.sh"`nfi`n`n# РџРѕРґРєР»СЋС‡Р°РµРј manifest`nif [[ -f "${SCRIPT_DIR}/lib/manifest.sh" ]]; then`n  source "${SCRIPT_DIR}/lib/manifest.sh"`nfi`n`n# в”Ђв”Ђ РљРѕРЅС„РёРіСѓСЂР°С†РёСЏ С‚РµСЃС‚РёСЂРѕРІР°РЅРёСЏ / Test Configuration в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`n`nTEST_RESULTS_DIR="/tmp/cubiveil-test-results"`nTEST_LOG_FILE="${TEST_RESULTS_DIR}/test.log"`n`n# РЎС‡С‘С‚С‡РёРєРё С‚РµСЃС‚РѕРІ`nTESTS_TOTAL=0`nTESTS_PASSED=0`nTESTS_FAILED=0`nTESTS_SKIPPED=0`n`n# в”Ђв”Ђ РРЅРёС†РёР°Р»РёР·Р°С†РёСЏ / Initialization в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`n`n# РРЅРёС†РёР°Р»РёР·Р°С†РёСЏ С‚РµСЃС‚РѕРІРѕР№ СЃСЂРµРґС‹`ntest_init() {`n  log_step "test_init" "Initializing test environment"`n`n  dir_ensure "$TEST_RESULTS_DIR"`n`n  # РћС‡РёС‰Р°РµРј Р»РѕРі-С„Р°Р№Р»`n  echo "" >"$TEST_LOG_FILE"`n`n  log_debug "Test environment initialized"`n}`n`n# в”Ђв”Ђ РЈС‚РёР»РёС‚С‹ С‚РµСЃС‚РёСЂРѕРІР°РЅРёСЏ / Test Utilities в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`n`n# Р’С‹РІРѕРґ СЂРµР·СѓР»СЊС‚Р°С‚Р° С‚РµСЃС‚Р°`ntest_result() {`n  local test_name="$1"`n  local result="$2"`n  local message="${3:-}"`n`n  ((TESTS_TOTAL++))`n`n  case "$result" in`n  pass)`n    ((TESTS_PASSED++)) || true`n    echo "[PASS] $test_name" | tee -a "$TEST_LOG_FILE"`n    ;;`n  fail)`n    ((TESTS_FAILED++)) || true`n    echo "[FAIL] $test_name" | tee -a "$TEST_LOG_FILE"`n    if [[ -n "$message" ]]; then`n      echo "       $message" | tee -a "$TEST_LOG_FILE"`n    fi`n    ;;`n  skip)`n    ((TESTS_SKIPPED++))`n    echo "[SKIP] $test_name: $message" | tee -a "$TEST_LOG_FILE"`n    ;;`n  esac`n}`n`n# в”Ђв”Ђ РўРµСЃС‚С‹ Core РјРѕРґСѓР»РµР№ / Core Module Tests в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`n`n# РўРµСЃС‚: Core РјРѕРґСѓР»Рё РґРѕСЃС‚СѓРїРЅС‹`ntest_core_modules_available() {`n  local test_name="Core modules availability"`n`n  if [[ -f "${SCRIPT_DIR}/lib/core/system.sh" ]] &&`n    [[ -f "${SCRIPT_DIR}/lib/core/log.sh" ]]; then`n    test_result "$test_name" "pass"`n  else`n    test_result "$test_name" "fail" "Core modules not found"`n  fi`n}`n`n# РўРµСЃС‚: РџСЂРѕРІРµСЂРєР° pkg_check`ntest_pkg_check() {`n  local test_name="pkg_check function"`n`n  if pkg_check "bash"; then`n    test_result "$test_name" "pass"`n  else`n    test_result "$test_name" "fail" "pkg_check not working"`n  fi`n}`n`n# РўРµСЃС‚: РџСЂРѕРІРµСЂРєР° svc_active`ntest_svc_active() {`n  local test_name="svc_active function"`n`n  # РџСЂРѕРІРµСЂСЏРµРј РЅРµСЃСѓС‰РµСЃС‚РІСѓСЋС‰РёР№ СЃРµСЂРІРёСЃ`n  if ! svc_active "nonexistent-service-12345"; then`n    test_result "$test_name" "pass"`n  else`n    test_result "$test_name" "fail" "svc_active not working correctly"`n  fi`n}`n`n# в”Ђв”Ђ РўРµСЃС‚С‹ Manifest / Manifest Tests в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`n`n# РўРµСЃС‚: Manifest Р·Р°РіСЂСѓР¶Р°РµС‚СЃСЏ`ntest_manifest_loads() {`n  local test_name="Manifest loading"`n`n  if declare -f manifest_list_all >/dev/null; then`n    test_result "$test_name" "pass"`n  else`n    test_result "$test_name" "fail" "Manifest not loaded"`n  fi`n}`n`n# РўРµСЃС‚: РџСЂРѕРІРµСЂРєР° РїРѕСЂСЏРґРєР° РјРѕРґСѓР»РµР№`ntest_manifest_order() {`n  local test_name="Manifest order validation"`n`n  local order`n  mapfile -t order < <(manifest_get_install_order)`n`n  if [[ ${#order[@]} -gt 0 ]]; then`n    test_result "$test_name" "pass" "Found ${#order[@]} modules"`n  else`n    test_result "$test_name" "fail" "No modules in order"`n  fi`n}`n`n# в”Ђв”Ђ РўРµСЃС‚С‹ РјРѕРґСѓР»РµР№ / Module Tests в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`n`n# РўРµСЃС‚: Firewall РјРѕРґСѓР»СЊ РґРѕСЃС‚СѓРїРµРЅ`ntest_firewall_module() {`n  local test_name="Firewall module availability"`n`n  local module_file="${SCRIPT_DIR}/lib/modules/firewall/install.sh"`n`n  if [[ -f "$module_file" ]]; then`n    test_result "$test_name" "pass"`n  else`n    test_result "$test_name" "fail" "Firewall module not found"`n  fi`n}`n`n# РўРµСЃС‚: Fail2ban РјРѕРґСѓР»СЊ РґРѕСЃС‚СѓРїРµРЅ`ntest_fail2ban_module() {`n  local test_name="Fail2ban module availability"`n`n  local module_file="${SCRIPT_DIR}/lib/modules/fail2ban/install.sh"`n`n  if [[ -f "$module_file" ]]; then`n    test_result "$test_name" "pass"`n  else`n    test_result "$test_name" "fail" "Fail2ban module not found"`n  fi`n}`n`n# РўРµСЃС‚: SSL РјРѕРґСѓР»СЊ РґРѕСЃС‚СѓРїРµРЅ`ntest_ssl_module() {`n  local test_name="SSL module availability"`n`n  local module_file="${SCRIPT_DIR}/lib/modules/ssl/install.sh"`n`n  if [[ -f "$module_file" ]]; then`n    test_result "$test_name" "pass"`n  else`n    test_result "$test_name" "fail" "SSL module not found"`n  fi`n}`n`n# РўРµСЃС‚: Singbox РјРѕРґСѓР»СЊ РґРѕСЃС‚СѓРїРµРЅ`ntest_singbox_module() {`n  local test_name="Singbox module availability"`n`n  local module_file="${SCRIPT_DIR}/lib/modules/singbox/install.sh"`n`n  if [[ -f "$module_file" ]]; then`n    test_result "$test_name" "pass"`n  else`n    test_result "$test_name" "fail" "Singbox module not found"`n  fi`n}`n`n# РўРµСЃС‚: System РјРѕРґСѓР»СЊ РґРѕСЃС‚СѓРїРµРЅ`ntest_system_module() {`n  local test_name="System module availability"`n`n  local module_file="${SCRIPT_DIR}/lib/modules/system/install.sh"`n`n  if [[ -f "$module_file" ]]; then`n    test_result "$test_name" "pass"`n  else`n    test_result "$test_name" "fail" "System module not found"`n  fi`n}`n`n# РўРµСЃС‚: Backup РјРѕРґСѓР»СЊ РґРѕСЃС‚СѓРїРµРЅ`ntest_backup_module() {`n  local test_name="Backup module availability"`n`n  local module_file="${SCRIPT_DIR}/lib/modules/backup/install.sh"`n`n  if [[ -f "$module_file" ]]; then`n    test_result "$test_name" "pass"`n  else`n    test_result "$test_name" "fail" "Backup module not found"`n  fi`n}`n`n# РўРµСЃС‚: Rollback РјРѕРґСѓР»СЊ РґРѕСЃС‚СѓРїРµРЅ`ntest_rollback_module() {`n  local test_name="Rollback module availability"`n`n  local module_file="${SCRIPT_DIR}/lib/modules/rollback/install.sh"`n`n  if [[ -f "$module_file" ]]; then`n    test_result "$test_name" "pass"`n  else`n    test_result "$test_name" "fail" "Rollback module not found"`n  fi`n}`n`n# РўРµСЃС‚: Monitoring РјРѕРґСѓР»СЊ РґРѕСЃС‚СѓРїРµРЅ`ntest_monitoring_module() {`n  local test_name="Monitoring module availability"`n`n  local module_file="${SCRIPT_DIR}/lib/modules/monitoring/install.sh"`n`n  if [[ -f "$module_file" ]]; then`n    test_result "$test_name" "pass"`n  else`n    test_result "$test_name" "fail" "Monitoring module not found"`n  fi`n}`n`n# в”Ђв”Ђ РўРµСЃС‚С‹ Step С„СѓРЅРєС†РёР№ / Step Functions Tests в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`n`n# РўРµСЃС‚: Step С„Р°Р№Р»С‹ РґРѕСЃС‚СѓРїРЅС‹`ntest_step_files_available() {`n  local test_name="Step files availability"`n`n  local steps_dir="${SCRIPT_DIR}/lib/steps"`n`n  if [[ -d "$steps_dir" ]]; then`n    local step_count`n    step_count=$(ls "$steps_dir"/*.sh 2>/dev/null | wc -l)`n`n    test_result "$test_name" "pass" "Found $step_count step files"`n  else`n    test_result "$test_name" "fail" "Steps directory not found"`n  fi`n}`n`n# в”Ђв”Ђ РўРµСЃС‚С‹ СѓС‚РёР»РёС‚ / Utility Tests в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`n`n# РўРµСЃС‚: Utils.sh РґРѕСЃС‚СѓРїРµРЅ`ntest_utils_available() {`n  local test_name="Utils.sh availability"`n`n  if [[ -f "${SCRIPT_DIR}/lib/utils.sh" ]]; then`n    test_result "$test_name" "pass"`n  else`n    test_result "$test_name" "fail" "Utils.sh not found"`n  fi`n}`n`n# РўРµСЃС‚: Validation.sh РґРѕСЃС‚СѓРїРµРЅ`ntest_validation_available() {`n  local test_name="Validation.sh availability"`n`n  if [[ -f "${SCRIPT_DIR}/lib/validation.sh" ]]; then`n    test_result "$test_name" "pass"`n  else`n    test_result "$test_name" "fail" "Validation.sh not found"`n  fi`n}`n`n# РўРµСЃС‚: Security.sh РґРѕСЃС‚СѓРїРµРЅ`ntest_security_available() {`n  local test_name="Security.sh availability"`n`n  if [[ -f "${SCRIPT_DIR}/lib/security.sh" ]]; then`n    test_result "$test_name" "pass"`n  else`n    test_result "$test_name" "fail" "Security.sh not found"`n  fi`n}`n`n# в”Ђв”Ђ Р—Р°РїСѓСЃРє РІСЃРµС… С‚РµСЃС‚РѕРІ / Run All Tests в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`n`n# Р—Р°РїСѓСЃРє РІСЃРµС… С‚РµСЃС‚РѕРІ`ntest_run_all() {`n  log_step "test_run_all" "Running all tests"`n`n  echo ""`n  echo "в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ"`n  echo "  CubiVeil Test Suite"`n  echo "в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ"`n  echo ""`n`n  # Core РјРѕРґСѓР»Рё`n  test_core_modules_available`n  test_pkg_check`n  test_svc_active`n`n  # Manifest`n  test_manifest_loads`n  test_manifest_order`n`n  # РњРѕРґСѓР»Рё`n  test_firewall_module`n  test_fail2ban_module`n  test_ssl_module`n  test_singbox_module`n  test_system_module`n  test_backup_module`n  test_rollback_module`n  test_monitoring_module`n`n  # Step С„СѓРЅРєС†РёРё`n  test_step_files_available`n`n  # РЈС‚РёР»РёС‚С‹`n  test_utils_available`n  test_validation_available`n  test_security_available`n`n  echo ""`n  echo "в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ"`n  echo ""`n}`n`n# РћС‚С‡С‘С‚ Рѕ С‚РµСЃС‚Р°С…`ntest_report() {`n  echo "в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ"`n  echo "  Test Results"`n  echo "в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ"`n  echo ""`n  echo "  Total:   $TESTS_TOTAL"`n  echo "  Passed:  $TESTS_PASSED"`n  echo "  Failed:  $TESTS_FAILED"`n  echo "  Skipped: $TESTS_SKIPPED"`n  echo ""`n`n  if [[ $TESTS_FAILED -eq 0 ]]; then`n    echo "  Status: вњ“ ALL TESTS PASSED"`n    echo ""`n    return 0`n  else`n    echo "  Status: вњ— SOME TESTS FAILED"`n    echo ""`n    echo "  Log file: $TEST_LOG_FILE"`n    echo ""`n    return 1`n  fi`n}`n`n# Р‘С‹СЃС‚СЂС‹Р№ С‚РµСЃС‚ (С‚РѕР»СЊРєРѕ РєСЂРёС‚РёС‡РЅС‹Рµ)`ntest_run_quick() {`n  log_step "test_run_quick" "Running quick tests"`n`n  test_core_modules_available`n  test_manifest_loads`n  test_system_module`n}`n`n# в”Ђв”Ђ РњРѕРґСѓР»СЊРЅС‹Р№ РёРЅС‚РµСЂС„РµР№СЃ / Module Interface в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`n`n# РЎС‚Р°РЅРґР°СЂС‚РЅС‹Р№ РёРЅС‚РµСЂС„РµР№СЃ РјРѕРґСѓР»СЏ`nmodule_install() { :; }`nmodule_configure() { :; }`nmodule_enable() { :; }`nmodule_disable() { :; }`n`n# Р—Р°РїСѓСЃРє РІСЃРµС… С‚РµСЃС‚РѕРІ`nmodule_test_all() {`n  test_init`n  test_run_all`n  test_report`n}`n`n# Р—Р°РїСѓСЃРє Р±С‹СЃС‚СЂС‹С… С‚РµСЃС‚РѕРІ`nmodule_test_quick() {`n  test_init`n  test_run_quick`n  test_report`n}`n`n# Р—Р°РїСѓСЃРє С‚РѕР»СЊРєРѕ РѕРїСЂРµРґРµР»С‘РЅРЅРѕРіРѕ С‚РµСЃС‚Р°`nmodule_test_one() {`n  local test_func="$1"`n`n  test_init`n`n  if declare -f "$test_func" >/dev/null; then`n    $test_func`n  else`n    log_error "Test function not found: $test_func"`n  fi`n`n  test_report`n}`n
